import {
  AfterViewChecked,
  AfterViewInit,
  Component,
  OnInit,
} from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { ReferencesService } from "src/app/core/services/references.service";
import { BranchModelResponse } from "../../Models/References/Branch";
import { OfficerService } from "src/app/core/services/officer.service";
import { IOfficer, officerResponseModal } from "../../Models/Officer/Officer";
import { ChangeDetectorRef } from "@angular/core";
import {
  GetAmlApplicationsRequest,
  GetAmlApplicationsResponse,
} from "../../Models/LoanApplication/GetAmlApplications";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { AlertService } from "src/app/core/services/alert.service";
import { FormStatus } from "../../Models/forms/formStatus";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { ExportingService } from "src/app/core/services/exporting.service";
import { OfficersVisitsWorkFlow } from "../../Models/Officer/OfficerVisitsWorkFlow";
import { GetDocumentsByClientKey } from "../../Models/Documents/GetDocumentByClientKey";
import { DocumentService } from "src/app/core/services/document.service";
import { documentInputData } from "../../Models/Documents/documentSlot";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";
import { IscoreHttpService } from "src/app/core/services/iscore-http.service";
import { HttpErrorResponse } from "@angular/common/http";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
interface GetAmlApplicationsResponseModified {
  clientName: string;
  approvedAmount: number;
  iscoreInquiryId: number | null;
  iScore: number;
  iscorePdfAvailable: boolean;
  amlRevisionStatus: number;
  amlRevisionNotes: string;
  applicationKey: number;
  useWorkFlow: number;
  branchName: string;
  officerName: string;
  entryDate: string;
  clientKey: number;
  havingDocuments: number;
  riskDesc: string;
}

interface documents {
  documentName: string | undefined;
  documentSlotInput: documentInputData | undefined;
}

@Component({
  selector: "app-aml-revision",
  templateUrl: "./aml-revision.page.html",
  styleUrls: ["./aml-revision.page.scss"],
})
export class AmlRevisionPage
  implements OnInit, AfterViewInit, AfterViewChecked
{
  constructor(
    private formBuilder: FormBuilder,
    private cdref: ChangeDetectorRef,
    private referencesService: ReferencesService,
    private officerService: OfficerService,
    private loanApplicationService: LoanApplicationsService,
    private alertService: AlertService,
    private sortingService: sortingService,
    public pagingService: pagingService,
    public exportingService: ExportingService,
    private documentService: DocumentService,
    private pdfViewerService: PdfViewerService,
    private iscoreHttpService: IscoreHttpService,
    public inputMaskingService: InputMaskingService
  ) {}
  //#region Variables
  showLoader: boolean = false;
  filterFormStatus: FormStatus = { valid: false, visible: true };
  applicationStatusArray: { name: string; value: number }[] = [
    {
      name: "لم يتم الانشاء",
      value: 1,
    },
    {
      name: "تم الانشاء و لم يتم الاصدار",
      value: 2,
    },
    {
      name: "تم الاصدار",
      value: 3,
    },
    {
      name: "مسدد بالكامل",
      value: 4,
    },
    {
      name: "مشكوك في السداد",
      value: 5,
    },
    {
      name: "مشطوب",
      value: 6,
    },
  ];
  branchModelResponse: BranchModelResponse[];
  officerModelResponse: officerResponseModal[] = [];
  gridFormStatus: FormStatus = { valid: false, visible: false };

  amlApplicationsGridData: GetAmlApplicationsResponseModified[];
  pagingObject: { page: number } = {
    page: 1, // the page we are viewing
  };
  sortingObject: { sortingIconClass: string; sortingIconParam: string } = {
    sortingIconClass: null,
    sortingIconParam: null,
  };
  timeLineObject: {
    visible: boolean;
    lastStep: OfficersVisitsWorkFlow[];
  } = { visible: false, lastStep: [] };

  clientDocumentsStatus: FormStatus = { valid: false, visible: false };
  clientDocuments: documents[] = [];

  iscoreInquiries: { inquiryId: number; inquiryPdfBase64: string }[] = [];
  //#endregion

  //#region Angular Hooks
  async ngOnInit() {
    this.branchModelResponse = await this.referencesService.getAllBranches();
    this.officerService.getAllOfficers().subscribe((officers) => {
      this.officerModelResponse = officers;
    });
  }
  async ngAfterViewInit() {
    this.filterForm.patchValue({
      startDate: null,
      endDate: null,
    });
  }
  async ngAfterViewChecked() {
    this.cdref.detectChanges();
  }
  //#endregion

  private async fetchAndCustomizeAmlApplicationFromDatabase(): Promise<
    GetAmlApplicationsResponseModified[]
  > {
    try {
      this.showLoader = true;
      const amlApplications = await this.loanApplicationService
        .getAmlApplications(this.extractAmlApplicationDataFromFormGroup())
        .toPromise();

      const customizedApplications = amlApplications.map((application) => ({
        ...application,
        amlRevisionStatus: 0,
        amlRevisionNotes: null,
      }));
      this.showLoader = false;
      return customizedApplications;
    } catch (error) {
      console.error("Error fetching AML applications:", error);
      this.showLoader = false;
      this.alertService.showAlertError(error?.error, false);
      throw error; // Rethrow the error for the calling code to handle
    }
  }

  public sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingObject.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingObject.sortingIconParam = param;
  }

  private extractClientsBeingRevised() {
    return (
      this.amlApplicationsGridData
        ?.filter((application) => application.amlRevisionStatus === 1)
        ?.map((application) => {
          return {
            applicationKey: application.applicationKey,
            appStatus: application.amlRevisionStatus,
            appNotes: application.amlRevisionNotes,
          };
        }) || []
    );
  }

  //#region Buttons
  public async filterSearchBtn() {
    this.filterFormStatus.valid = true;
    if (!this.filterForm.valid) return;
    this.amlApplicationsGridData =
      await this.fetchAndCustomizeAmlApplicationFromDatabase();
    this.gridFormStatus.visible = true;
  }
  public async openTimeLineBtn(applicationKey: number) {
    try {
      this.showLoader = true;
      this.timeLineObject.lastStep =
        await this.loanApplicationService.getLastSteps(
          applicationKey?.toString()
        );
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
      return this.alertService.showAlertError(error?.error, false);
    }
    if (this.timeLineObject.lastStep.length === 0)
      return this.alertService.showAlertError("لا يوجد بيانات", false);
    this.gridFormStatus.visible = false;
    this.filterFormStatus.visible = false;
    this.timeLineObject.visible = !this.timeLineObject.visible;
  }
  public backButton() {
    const filterVisible: boolean = this.filterFormStatus.visible;
    const gridVisible: boolean = this.gridFormStatus.visible;
    const timeLineVisible: boolean = this.timeLineObject.visible;
    const documentVisible: boolean = this.clientDocumentsStatus.visible;
    if (timeLineVisible && !filterVisible && !gridVisible) {
      this.timeLineObject.visible = false;
      this.filterFormStatus.visible = true;
      this.gridFormStatus.visible = true;
    }
    if (documentVisible && !timeLineVisible && !filterVisible && !gridVisible) {
      this.clientDocumentsStatus.visible = false;
      this.filterFormStatus.visible = true;
      this.gridFormStatus.visible = true;
    }
  }
  public async savingAmlResultBtn() {
    try {
      const amlApplicationToSave = this.extractClientsBeingRevised();
      if (amlApplicationToSave.length === 0) {
        return this.alertService.showAlertError("برجاء اختيار العميل", false);
      }
      if (!(await this.alertService.SaveAlert())) return;
      const json = JSON.stringify(amlApplicationToSave);

      this.showLoader = true;
      await this.loanApplicationService.amlRevisionApprove(json).toPromise();
      this.showLoader = false;
      this.alertService.showAlertConfirm("لقد تم المراجعة", true);
    } catch (error) {
      console.error("Error in savingAmlResultBtn:", error);
      this.showLoader = false;
      return this.alertService.showAlertError(error?.error, false);
    }
  }
  public async openDocumentsBtn(clientKey: number) {
    try {
      this.showLoader = true;
      const documents = await this.documentService
        .getDocumentsForClientPerClientKey(clientKey)
        .toPromise();
      this.showLoader = false;

      if (!documents) {
        return this.alertService.showAlertError("لا يوجد مستندات للعرض", false);
      }

      this.clientDocuments = documents.map((doc) => ({
        documentSlotInput: {
          canEdit: false,
          loanTypeCode: String(doc.documentTypeCode),
          uploadedDocuments: doc.documentImage.map((x) => ({ doc: x })),
        },
        documentName: doc.documentTypeDescription,
      }));
      console.log(this.clientDocuments);
      console.log(documents);
      this.clientDocumentsStatus.visible = true;
      this.filterFormStatus.visible = false;
      this.gridFormStatus.visible = false;
    } catch (error) {
      this.showLoader = false;
      this.alertService.showAlertError(error?.error || "حدث خطأ", false);
    }
  }
  //#endregion

  //#region Changing Events
  async amlStatusCheckBoxChange(clientData: GetAmlApplicationsResponse) {
    const index = this.amlApplicationsGridData.findIndex((object) => {
      return object.applicationKey === clientData.applicationKey;
    });

    if (index !== -1) {
      this.amlApplicationsGridData[index].amlRevisionStatus =
        this.amlApplicationsGridData[index].amlRevisionStatus === 0 ? 1 : 0;
    }
  }
  async amlNoteChanging(clientData: GetAmlApplicationsResponse, event: any) {
    const index = this.amlApplicationsGridData.findIndex((object) => {
      return object.applicationKey === clientData.applicationKey;
    });

    if (index !== -1) {
      this.amlApplicationsGridData[index].amlRevisionNotes =
        this.amlApplicationsGridData[index].amlRevisionNotes =
          event.detail["value"] == ""
            ? null
            : (this.amlApplicationsGridData[index].amlRevisionNotes =
                event.detail["value"]);
    }
  }
  changingApplicationStatus() {
    let applicationStatusValue: number =
      this.filterForm.controls["applicationStatus"].value;
    switch (applicationStatusValue) {
      case 1:
        this.filterForm.patchValue({
          loanGenerateStatus: 0,
          loanStatus: 0,
          loanCondition: null,
        });
        break;
      case 2:
        this.filterForm.patchValue({
          loanGenerateStatus: 1,
          loanStatus: 0,
          loanCondition: null,
        });
        break;
      case 3:
        this.filterForm.patchValue({
          loanGenerateStatus: 1,
          loanStatus: 1,
          loanCondition: null,
        });
        break;
      case 4:
        this.filterForm.patchValue({
          loanGenerateStatus: 1,
          loanStatus: 5,
          loanCondition: null,
        });
        break;
      case 5:
        this.filterForm.patchValue({
          loanGenerateStatus: 1,
          loanStatus: 1,
          loanCondition: 1,
        });
        break;
      case 6:
        this.filterForm.patchValue({
          loanGenerateStatus: 1,
          loanStatus: 1,
          loanCondition: 2,
        });
        break;
    }
  }
  changePaginationPage = (newPage: number): void => {
    this.pagingObject.page = newPage;
  };
  //#endregion

  //#region FormsGroup
  filterForm: FormGroup = this.formBuilder.group({
    applicationStatus: [null, Validators.required],
    branch: ["00"],
    officer: ["00"],
    startDate: [null],
    endDate: [null],
    loanGenerateStatus: [null],
    loanStatus: [null],
    requestAmountFrom: [null],
    requestAmountTo: [null],
    loanCondition: [null],
  });
  private extractAmlApplicationDataFromFormGroup(): GetAmlApplicationsRequest {
    return {
      branch_code:
        this.filterForm.controls["branch"].value === "00"
          ? null
          : this.filterForm.controls["branch"].value,
      start_date: this.filterForm.controls["startDate"].value,
      end_date: this.filterForm.controls["endDate"].value,
      loan_status: this.filterForm.controls["loanStatus"].value,
      loan_gen_status: this.filterForm.controls["loanGenerateStatus"].value,
      officer_key:
        this.filterForm.controls["officer"].value === "00"
          ? null
          : this.filterForm.controls["officer"].value,
      request_amount_from: this.filterForm.controls["requestAmountFrom"].value,
      request_amount_to: this.filterForm.controls["requestAmountTo"].value,
      loan_cond: this.filterForm.controls["loanCondition"].value,
    };
  }
  //#endregion

  public async showInquiryPdf(inquiryId: number) {
    if (!this.pdfViewerService.canViewPdf()) {
      await this.alertService.showAlertError(
        "لا يمكن عرض أو تنزيل المستند على المتصفح الحالي",
        false
      );
      return;
    }

    await this.getInquiryPdf(inquiryId);

    await this.pdfViewerService.viewPdf(
      this.iscoreInquiries.find((inquiry) => inquiry.inquiryId == inquiryId)
        .inquiryPdfBase64!,
      `inquiry_${inquiryId}.pdf`,
      "تقرير الاستعلام الائتماني"
    );
  }

  private async getInquiryPdf(inquiryId: number) {
    if (
      !this.iscoreInquiries.some((inquiry) => inquiry.inquiryId == inquiryId)
    ) {
      this.showLoader = true;

      try {
        const pdfResponse = await this.iscoreHttpService
          .getInquiryPdf(inquiryId)
          .toPromise();

        this.iscoreInquiries = [
          ...this.iscoreInquiries.slice(-2),
          { inquiryId, inquiryPdfBase64: pdfResponse.base64String },
        ];

        this.showLoader = false;
      } catch (err) {
        this.showLoader = false;
        if (err instanceof HttpErrorResponse) {
          this.alertService.showAlertError(JSON.stringify(err.error), false);
          return;
        }
      }
    }
  }
}
